import{_ as t,o as a,c as o,a3 as r}from"./chunks/framework.DACwFHq9.js";const c=JSON.parse('{"title":"Settings Reference","description":"","frontmatter":{},"headers":[],"relativePath":"settings-reference.md","filePath":"settings-reference.md","lastUpdated":1784212824000}'),n={name:"settings-reference.md"};function i(s,e,l,d,h,u){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="settings-reference" tabindex="-1">Settings Reference <a class="header-anchor" href="#settings-reference" aria-label="Permalink to &quot;Settings Reference&quot;">​</a></h1><p>Use this page when you want to understand what each configurable option does in Notely.</p><h2 id="_1-appearance" tabindex="-1">1. Appearance <a class="header-anchor" href="#_1-appearance" aria-label="Permalink to &quot;1. Appearance&quot;">​</a></h2><h3 id="theme" tabindex="-1">Theme <a class="header-anchor" href="#theme" aria-label="Permalink to &quot;Theme&quot;">​</a></h3><p>Open <strong>Settings -&gt; Theme</strong>.</p><ul><li><strong>System</strong>: follows the operating system theme</li><li><strong>Light</strong>: always uses the light theme</li><li><strong>Dark</strong>: always uses the dark theme</li></ul><p>Default: <strong>System</strong></p><p>Use this when you want Notely to stay consistent with your desktop or when you need a fixed light or dark theme.</p><h3 id="zoom" tabindex="-1">Zoom <a class="header-anchor" href="#zoom" aria-label="Permalink to &quot;Zoom&quot;">​</a></h3><p>Open <strong>View -&gt; Zoom In</strong>, <strong>Zoom Out</strong>, or <strong>Reset Zoom</strong>.</p><ul><li>Minimum zoom: 75%</li><li>Default zoom: 80%</li><li>Maximum zoom: 200%</li></ul><p>Use zoom when UI text or panels feel too small or too large on your display.</p><h2 id="_2-landing-view" tabindex="-1">2. Landing View <a class="header-anchor" href="#_2-landing-view" aria-label="Permalink to &quot;2. Landing View&quot;">​</a></h2><h3 id="view-mode" tabindex="-1">View Mode <a class="header-anchor" href="#view-mode" aria-label="Permalink to &quot;View Mode&quot;">​</a></h3><p>Open <strong>View -&gt; Tile Notes</strong> or <strong>View -&gt; Table Notes</strong>.</p><ul><li><strong>Tile Notes</strong>: visual cards with previews and summary details</li><li><strong>Table Notes</strong>: denser list-style view for scanning many notes quickly</li></ul><h3 id="density" tabindex="-1">Density <a class="header-anchor" href="#density" aria-label="Permalink to &quot;Density&quot;">​</a></h3><p>Open <strong>View -&gt; Comfortable Density</strong> or <strong>Compact Density</strong>.</p><ul><li><strong>Comfortable</strong>: more whitespace and larger rows</li><li><strong>Compact</strong>: denser rows for large workspaces</li></ul><p>Use compact density when you want to see more notes at once.</p><h2 id="_3-editor-and-writing" tabindex="-1">3. Editor and Writing <a class="header-anchor" href="#_3-editor-and-writing" aria-label="Permalink to &quot;3. Editor and Writing&quot;">​</a></h2><h3 id="typo-check" tabindex="-1">Typo Check <a class="header-anchor" href="#typo-check" aria-label="Permalink to &quot;Typo Check&quot;">​</a></h3><p>Open <strong>Edit -&gt; Enable Typo Check</strong>.</p><ul><li>When enabled, Notely checks note text for spelling and typo issues.</li><li>It skips code and diagram content so it does not flag technical text unnecessarily.</li></ul><p>Default: <strong>On</strong></p><h3 id="outline" tabindex="-1">Outline <a class="header-anchor" href="#outline" aria-label="Permalink to &quot;Outline&quot;">​</a></h3><p>Open <strong>View -&gt; Show Outline</strong>.</p><ul><li>Shows a headings-based side panel for the current note</li><li>Hidden automatically while Focus Mode is active</li></ul><p>Shortcut: <code>Ctrl/Cmd + Alt + L</code></p><h3 id="focus-mode" tabindex="-1">Focus Mode <a class="header-anchor" href="#focus-mode" aria-label="Permalink to &quot;Focus Mode&quot;">​</a></h3><p>Open <strong>View -&gt; Focus Mode</strong>.</p><ul><li>Hides the outline and reduces surrounding distractions</li><li>Useful for concentrated writing sessions</li></ul><p>Shortcut: <code>Ctrl/Cmd + Alt + F</code></p><h2 id="_4-terminal" tabindex="-1">4. Terminal <a class="header-anchor" href="#_4-terminal" aria-label="Permalink to &quot;4. Terminal&quot;">​</a></h2><h3 id="show-terminal" tabindex="-1">Show Terminal <a class="header-anchor" href="#show-terminal" aria-label="Permalink to &quot;Show Terminal&quot;">​</a></h3><p>Open <strong>View -&gt; Show Terminal</strong>.</p><ul><li>Opens or hides the embedded terminal panel</li><li>Useful for project-local commands while staying in Notely</li></ul><h3 id="terminal-shell" tabindex="-1">Terminal Shell <a class="header-anchor" href="#terminal-shell" aria-label="Permalink to &quot;Terminal Shell&quot;">​</a></h3><p>Open <strong>View -&gt; Terminal Shell</strong>.</p><ul><li><strong>Auto</strong>: lets Notely choose the shell</li><li><strong>Bash</strong>: prefers Bash when available</li><li><strong>CMD</strong>: uses Windows Command Prompt</li></ul><p>Use Bash if you prefer a Unix-style command line. Use CMD if you prefer standard Windows commands.</p><h2 id="_5-screen-capture" tabindex="-1">5. Screen Capture <a class="header-anchor" href="#_5-screen-capture" aria-label="Permalink to &quot;5. Screen Capture&quot;">​</a></h2><p>Open <strong>Settings -&gt; Screen Capture</strong>.</p><ul><li><strong>Auto Insert</strong>: inserts the captured image immediately into the note</li><li><strong>Review Before Insert</strong>: opens the review editor before saving and inserting</li></ul><p>Default: <strong>Auto Insert</strong></p><p>The toolbar capture button shows the current mode:</p><ul><li><code>A</code> = Auto Insert</li><li><code>R</code> = Review Before Insert</li></ul><h2 id="_6-ai-settings" tabindex="-1">6. AI Settings <a class="header-anchor" href="#_6-ai-settings" aria-label="Permalink to &quot;6. AI Settings&quot;">​</a></h2><p>Open <strong>AI -&gt; AI Settings</strong>.</p><h3 id="provider-setup" tabindex="-1">Provider setup <a class="header-anchor" href="#provider-setup" aria-label="Permalink to &quot;Provider setup&quot;">​</a></h3><ul><li><strong>Text provider</strong>: choose the AI service that writes or rewrites text for you</li><li><strong>HuggingFace token</strong>: turns on meaning-based search and the smarter graph view</li><li><strong>Test</strong> buttons: check that your saved sign-in details work</li></ul><p>Current UI status:</p><ul><li><strong>OpenAI</strong> and <strong>Local LLM</strong> are visible as planned providers and are not currently configurable</li></ul><h3 id="feature-toggles" tabindex="-1">Feature toggles <a class="header-anchor" href="#feature-toggles" aria-label="Permalink to &quot;Feature toggles&quot;">​</a></h3><ul><li><strong>Learn user patterns</strong>: lets the app remember how you use AI so it can be more helpful later</li><li><strong>Generate embeddings</strong>: turns on meaning-based search and related-note features</li><li><strong>Discover relationships</strong>: helps the graph and AI features find links between related notes</li></ul><h3 id="advanced-generation-tuning" tabindex="-1">Advanced generation tuning <a class="header-anchor" href="#advanced-generation-tuning" aria-label="Permalink to &quot;Advanced generation tuning&quot;">​</a></h3><ul><li><strong>Max tokens</strong>: controls how long AI responses are allowed to be</li><li><strong>Temperature</strong>: controls how safe and predictable, or how varied and creative, the response feels</li></ul><p>Use lower temperature for predictable output. Use higher temperature for brainstorming or variation.</p><h3 id="data-and-privacy-controls" tabindex="-1">Data and privacy controls <a class="header-anchor" href="#data-and-privacy-controls" aria-label="Permalink to &quot;Data and privacy controls&quot;">​</a></h3><ul><li>Shows where AI-related app data is stored on your device</li><li>Lets you clear saved AI working data and learned behavior</li></ul><h2 id="_7-workspace-metadata-and-git-safety" tabindex="-1">7. Workspace Metadata and Git Safety <a class="header-anchor" href="#_7-workspace-metadata-and-git-safety" aria-label="Permalink to &quot;7. Workspace Metadata and Git Safety&quot;">​</a></h2><p>If your workspace is also a Git folder, Notely can help keep its own support files out of version control.</p><ul><li><strong>Ignore .notes-app: On</strong>: automatically keeps <code>.notes-app/</code> ignored in <code>.gitignore</code></li><li><strong>Ignore .notes-app: Off</strong>: leaves Git ignore management to you</li></ul><p>Use this when your team stores notes in Git but does not want Notely&#39;s private support files committed with them.</p>',64)])])}const p=t(n,[["render",i]]);export{c as __pageData,p as default};
